// 对当前文档应用公文排版规范
var doc = Application.ActiveDocument;
if (!doc) {
    return '未找到活动文档';
}

// 设置页面边距（公文标准：上3.7cm, 下3.5cm, 左2.8cm, 右2.6cm）
var pageSetup = doc.PageSetup;
pageSetup.TopMargin = 3.7 * 28.3465; // 转换为磅
pageSetup.BottomMargin = 3.5 * 28.3465;
pageSetup.LeftMargin = 2.8 * 28.3465;
pageSetup.RightMargin = 2.6 * 28.3465;

// 遍历所有段落进行格式设置
var paragraphs = doc.Content.Paragraphs;
for (var i = 0; i < paragraphs.Count; i++) {
    var para = paragraphs.Item(i + 1); // WPS JS 索引从1开始
    var text = para.Range.Text;

    // 去除末尾的换行符判断是否为标题
    var cleanText = text.replace(/[\r\n]+$/, '');

    if (cleanText.length > 0) {
        // 判断是否为标题（根据内容特征）
        if (cleanText.indexOf('采购申请') >= 0 && cleanText.length < 20) {
            // 主标题：二号小标宋体，居中
            para.Range.Font.Name = '小标宋';
            para.Range.Font.Size = 22; // 二号约22磅
            para.Alignment = 1; // 居中
            para.SpaceBefore = 0;
            para.SpaceAfter = 24; // 段后间距
        } else if (cleanText.match(/^一、|^二、|^三、/)) {
            // 一级标题：黑体，三号
            para.Range.Font.Name = '黑体';
            para.Range.Font.Size = 16; // 三号约16磅
            para.SpaceBefore = 12;
            para.SpaceAfter = 6;
        } else if (cleanText.match(/^（一）|^（二）|^（三）/)) {
            // 二级标题：楷体，三号
            para.Range.Font.Name = '楷体';
            para.Range.Font.Size = 16;
            para.SpaceBefore = 6;
            para.SpaceAfter = 0;
        } else if (cleanText.match(/^\d+\.|^\(1\)|^\(2\)/)) {
            // 三级标题：仿宋加粗，三号
            para.Range.Font.Name = '仿宋';
            para.Range.Font.Size = 16;
            para.Range.Font.Bold = true;
            para.SpaceBefore = 0;
            para.SpaceAfter = 0;
        } else {
            // 正文：仿宋，三号，行距固定值28磅
            para.Range.Font.Name = '仿宋';
            para.Range.Font.Size = 16;
            para.Format.LineRule = true;
            para.Format.LineSpacing = 28; // 固定值28磅
            para.SpaceBefore = 0;
            para.SpaceAfter = 0;
        }
    }
}

return '公文排版已完成：已设置页边距、标题样式和正文字体行距';
